"""Main CLI entry point for att-gateway-check"""

import argparse
import logging
import sys

from . import __version__
from .config import Config, DEFAULT_CONFIG_PATH
from .gateway import ATTGateway
from .checks import ConfigurationChecker


def setup_logging(level=logging.INFO):
    """Configure logging for the application.

    Args:
        level: Logging level
    """
    logging.basicConfig(
        level=level,
        format='%(levelname)s %(message)s',
        stream=sys.stdout
    )


def cmd_check(args):
    """Run configuration check mode.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2
    except Exception as e:
        log.error(f"Failed to load configuration: {e}")
        return 2

    # Set up logging level from config
    setup_logging(config.get_log_level())

    # Connect to gateway
    try:
        gateway = ATTGateway(
            host=config.get_gateway_host(),
            password=config.get_gateway_password()
        )
        gateway.login()
    except Exception as e:
        log.error(f"Failed to connect to gateway: {e}")
        return 2

    # Override auto-fix if requested
    if args.no_fix:
        log.info("Auto-fix disabled by command line flag")
        # Temporarily disable auto-fix
        original_auto_fix = config.parser.get('check', 'auto_fix', fallback='true')
        config.parser.set('check', 'auto_fix', 'false')

    # Run checks
    try:
        checker = ConfigurationChecker(gateway, config)
        exit_code = checker.run_all_checks()
        return exit_code
    except Exception as e:
        log.error(f"Check failed with error: {e}", exc_info=True)
        return 2


def cmd_gateway_info(args):
    """Show gateway firmware version and compatibility info.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2

    # Connect to gateway
    try:
        gateway = ATTGateway(
            host=config.get_gateway_host(),
            password=config.get_gateway_password()
        )
        gateway.login()

        print("=" * 60)
        print("AT&T Gateway Information")
        print("=" * 60)
        print(f"Host:             {gateway.host}")
        print(f"Firmware Version: {gateway.firmware_version}")
        print(f"Handler:          {gateway.handler.__class__.__name__}")
        print(f"Handler Version:  {gateway.handler.version}")
        print("=" * 60)

        return 0

    except Exception as e:
        log.error(f"Failed to get gateway info: {e}")
        return 2


def cmd_version(args):
    """Show program version.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    print(f"att-gateway-check version {__version__}")
    return 0


def cmd_backup(args):
    """Run backup mode.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2

    setup_logging(config.get_log_level())

    # Connect to gateway
    try:
        from .gateway import ATTGateway
        from .backup import BackupManager
        from .discovery import PageDiscovery

        gateway = ATTGateway(
            host=config.get_gateway_host(),
            password=config.get_gateway_password()
        )
        gateway.login()

        # Run discovery if requested
        if args.discover:
            log.info("Running page discovery...")
            discovery = PageDiscovery(gateway)
            discovery.discover(force=True)

        # Create backup
        backup_mgr = BackupManager(gateway, config)
        backup_file = backup_mgr.create_backup()

        log.info(f"Backup complete: {backup_file}")
        return 0

    except Exception as e:
        log.error(f"Backup failed: {e}", exc_info=True)
        return 2


def cmd_restore(args):
    """Run restore mode.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2

    setup_logging(config.get_log_level())

    # Connect to gateway
    try:
        from .gateway import ATTGateway
        from .backup import BackupManager
        from .restore import RestoreManager

        gateway = ATTGateway(
            host=config.get_gateway_host(),
            password=config.get_gateway_password()
        )
        gateway.login()

        backup_mgr = BackupManager(gateway, config)
        restore_mgr = RestoreManager(gateway, backup_mgr)

        # Parse page list if provided
        pages = None
        if args.page:
            pages = [args.page] if isinstance(args.page, str) else args.page

        # Run restore
        success = restore_mgr.restore(
            backup_identifier=args.backup,
            pages=pages,
            dry_run=args.dry_run
        )

        return 0 if success else 2

    except Exception as e:
        log.error(f"Restore failed: {e}", exc_info=True)
        return 2


def cmd_discover(args):
    """Run discovery mode.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2

    setup_logging(config.get_log_level())

    # Connect to gateway
    try:
        from .gateway import ATTGateway
        from .discovery import PageDiscovery

        gateway = ATTGateway(
            host=config.get_gateway_host(),
            password=config.get_gateway_password()
        )
        gateway.login()

        # Run discovery
        discovery = PageDiscovery(gateway)
        pages = discovery.discover(force=args.force)

        # Print summary
        discovery.print_summary()

        return 0

    except Exception as e:
        log.error(f"Discovery failed: {e}", exc_info=True)
        return 2


def cmd_list_backups(args):
    """List available backups.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2

    from .backup import BackupManager

    # Create backup manager (doesn't need gateway connection)
    backup_mgr = BackupManager(None, config)
    backup_mgr.print_backup_list()

    return 0


def cmd_diff_backup(args):
    """Show diff between current config and backup.

    Args:
        args: Parsed command-line arguments

    Returns:
        Exit code
    """
    log = logging.getLogger(__name__)

    # Load configuration
    try:
        config = Config(args.config)
        config.load()
    except FileNotFoundError as e:
        log.error(str(e))
        return 2

    setup_logging(config.get_log_level())

    # Connect to gateway
    try:
        from .gateway import ATTGateway
        from .backup import BackupManager
        from .restore import RestoreManager

        gateway = ATTGateway(
            host=config.get_gateway_host(),
            password=config.get_gateway_password()
        )
        gateway.login()

        backup_mgr = BackupManager(gateway, config)
        restore_mgr = RestoreManager(gateway, backup_mgr)

        success = restore_mgr.diff_backup(args.backup)

        return 0 if success else 2

    except Exception as e:
        log.error(f"Diff failed: {e}", exc_info=True)
        return 2


def main():
    """Main entry point."""
    parser = argparse.ArgumentParser(
        prog='att-gateway-check',
        description='AT&T BGW320-500 Gateway Configuration Manager'
    )

    parser.add_argument(
        '-c', '--config',
        default=DEFAULT_CONFIG_PATH,
        help=f'Configuration file (default: {DEFAULT_CONFIG_PATH})'
    )

    subparsers = parser.add_subparsers(dest='command', help='Command to run')

    # check command
    check_parser = subparsers.add_parser(
        'check',
        help='Check and fix gateway configuration'
    )
    check_parser.add_argument(
        '--no-fix',
        action='store_true',
        help='Check only, do not auto-fix issues'
    )
    check_parser.set_defaults(func=cmd_check)

    # gateway-info command
    info_parser = subparsers.add_parser(
        'gateway-info',
        help='Show gateway firmware version and compatibility'
    )
    info_parser.set_defaults(func=cmd_gateway_info)

    # version command
    version_parser = subparsers.add_parser(
        'version',
        help='Show program version'
    )
    version_parser.set_defaults(func=cmd_version)

    # backup command (stub)
    backup_parser = subparsers.add_parser(
        'backup',
        help='Backup gateway configuration'
    )
    backup_parser.add_argument(
        '--discover',
        action='store_true',
        help='Re-run page discovery before backup'
    )
    backup_parser.set_defaults(func=cmd_backup)

    # restore command (stub)
    restore_parser = subparsers.add_parser(
        'restore',
        help='Restore gateway configuration from backup'
    )
    restore_parser.add_argument(
        '--backup',
        help='Specific backup timestamp to restore'
    )
    restore_parser.add_argument(
        '--page',
        help='Restore only a specific page'
    )
    restore_parser.add_argument(
        '--dry-run',
        action='store_true',
        help='Show what would change without applying'
    )
    restore_parser.set_defaults(func=cmd_restore)

    # discover command (stub)
    discover_parser = subparsers.add_parser(
        'discover',
        help='Discover all gateway configuration pages'
    )
    discover_parser.add_argument(
        '--force',
        action='store_true',
        help='Force re-discovery (ignore cache)'
    )
    discover_parser.set_defaults(func=cmd_discover)

    # list-backups command
    list_parser = subparsers.add_parser(
        'list-backups',
        help='List available backups'
    )
    list_parser.set_defaults(func=cmd_list_backups)

    # diff-backup command
    diff_parser = subparsers.add_parser(
        'diff-backup',
        help='Show differences between current config and backup'
    )
    diff_parser.add_argument(
        'backup',
        nargs='?',
        help='Backup timestamp to compare (default: latest)'
    )
    diff_parser.set_defaults(func=cmd_diff_backup)

    # Parse arguments
    args = parser.parse_args()

    # Default to check command if no command specified
    if not args.command:
        args.command = 'check'
        args.func = cmd_check
        args.no_fix = False

    # Set up basic logging
    setup_logging()

    # Run command
    try:
        exit_code = args.func(args)
        sys.exit(exit_code)
    except KeyboardInterrupt:
        print("\nInterrupted by user")
        sys.exit(130)
    except Exception as e:
        logging.error(f"Unexpected error: {e}", exc_info=True)
        sys.exit(2)


if __name__ == '__main__':
    main()
